// galeria.js — Galería de trabajos por constructor
(function () {

    const STORAGE_PREFIX = 'mom_galeria_';

    function obtenerGaleria(id) {
        try { return JSON.parse(localStorage.getItem(STORAGE_PREFIX + id) || '[]'); }
        catch { return []; }
    }

    function guardarGaleria(id, fotos) {
        localStorage.setItem(STORAGE_PREFIX + id, JSON.stringify(fotos));
    }

    // Fotos semilla — solo se aplican si la galería del constructor está vacía
    const SEEDS = {
        2: [
            { src: 'data:image/jpeg;base64,', caption: 'Estructura metálica — bodega 200 m\u00b2', fecha: '26/06/2026' },
            { src: 'data:image/jpeg;base64,', caption: 'Instalaci\u00f3n el\u00e9ctrica subterr\u00e1nea', fecha: '26/06/2026' }
        ]
    };
    (function () {
        var FLAG = 'mom_galeria_seeds_v2';
        if (localStorage.getItem(FLAG)) return;
        Object.keys(SEEDS).forEach(function (id) {
            if (obtenerGaleria(id).length === 0) guardarGaleria(id, SEEDS[id]);
        });
        localStorage.setItem(FLAG, '1');
    })();

    function obtenerSesion() {
        try { return JSON.parse(localStorage.getItem('mom_sesion') || 'null'); } catch { return null; }
    }

    function esConstructorDueno(constructorId) {
        var sesion = obtenerSesion();
        if (!sesion || sesion.rol !== 'constructor') return false;
        if (typeof todosLosConstructores === 'undefined') return false;
        var c = todosLosConstructores.find(function(x) { return x.id === constructorId; });
        if (!c) return false;
        return (c.userId && c.userId === sesion.id) || c.nombre === sesion.nombre;
    }

    function crearModal() {
        if (document.getElementById('galeriaModal')) return;
        var overlay = document.createElement('div');
        overlay.id = 'galeriaModal';
        overlay.className = 'modal-overlay';
        overlay.style.zIndex = '2500';
        overlay.innerHTML = '<div class="modal-box" style="max-width:680px;width:min(95%,680px);padding:28px 24px;">'
            + '<button class="modal-close" id="galeriaModalClose">&times;</button>'
            + '<h3 id="galeriaTitulo" style="font-size:1.25rem;margin-bottom:6px;">Galer\u00eda de trabajos</h3>'
            + '<p id="galeriaSubtitulo" style="font-size:0.85rem;color:#888;margin-bottom:18px;text-align:center;"></p>'
            + '<div id="galeriaUploadZona" style="display:none;margin-bottom:20px;">'
            +   '<label id="galeriaUploadLabel" style="display:flex;flex-direction:column;align-items:center;gap:8px;border:2px dashed #c0392b;border-radius:12px;padding:20px;cursor:pointer;background:#fff5f5;">'
            +     '<svg viewBox="0 0 24 24" width="32" height="32" fill="none" stroke="#c0392b" stroke-width="1.8"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>'
            +     '<span style="color:#c0392b;font-weight:600;font-size:0.9rem;">Subir fotos de trabajos</span>'
            +     '<span style="color:#aaa;font-size:0.78rem;">JPG, PNG o WebP \u00b7 M\u00e1x. 5 MB</span>'
            +     '<input id="galeriaFileInput" type="file" accept="image/*" multiple style="display:none;">'
            +   '</label>'
            +   '<p id="galeriaUploadError" style="color:#c62828;font-size:0.82rem;margin-top:6px;display:none;text-align:center;"></p>'
            + '</div>'
            + '<div id="galeriaGrid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;max-height:50vh;overflow-y:auto;padding-right:4px;"></div>'
            + '<p id="galeriaVacia" style="text-align:center;color:#aaa;font-size:0.95rem;padding:30px 0;display:none;">A\u00fan no hay fotos en esta galer\u00eda.</p>'
            + '<div id="galeriaLightbox" style="display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.88);z-index:3500;justify-content:center;align-items:center;flex-direction:column;gap:16px;">'
            +   '<button id="galeriaLightboxClose" style="position:absolute;top:18px;right:22px;background:none;border:none;color:white;font-size:2.2rem;cursor:pointer;">&times;</button>'
            +   '<img id="galeriaLightboxImg" src="" alt="" style="max-width:90vw;max-height:80vh;border-radius:10px;object-fit:contain;">'
            +   '<p id="galeriaLightboxCaption" style="color:#ddd;font-size:0.88rem;text-align:center;padding:0 20px;max-width:600px;"></p>'
            + '</div>'
            + '</div>';
        document.body.appendChild(overlay);
        overlay.addEventListener('click', function (e) { if (e.target === overlay) cerrarModal(); });
        document.getElementById('galeriaModalClose').addEventListener('click', cerrarModal);
        document.getElementById('galeriaLightboxClose').addEventListener('click', function () {
            document.getElementById('galeriaLightbox').style.display = 'none';
        });
        document.getElementById('galeriaLightbox').addEventListener('click', function (e) {
            if (e.target === this) this.style.display = 'none';
        });
        document.getElementById('galeriaFileInput').addEventListener('change', manejarArchivos);
    }

    var idActivo = null;

    function abrirGaleriaModal(constructorId, nombre) {
        crearModal();
        idActivo = constructorId;
        document.getElementById('galeriaTitulo').textContent = 'Galer\u00eda de trabajos';
        document.getElementById('galeriaSubtitulo').textContent = nombre || '';
        document.getElementById('galeriaUploadError').style.display = 'none';
        document.getElementById('galeriaUploadZona').style.display = esConstructorDueno(constructorId) ? 'block' : 'none';
        renderGrid(constructorId);
        document.getElementById('galeriaModal').classList.add('open');
    }

    function cerrarModal() {
        var m = document.getElementById('galeriaModal');
        if (m) m.classList.remove('open');
        idActivo = null;
    }

    function renderGrid(constructorId) {
        var fotos = obtenerGaleria(constructorId);
        var grid = document.getElementById('galeriaGrid');
        var vacia = document.getElementById('galeriaVacia');
        var esDueno = esConstructorDueno(constructorId);
        grid.innerHTML = '';
        if (fotos.length === 0) { vacia.style.display = 'block'; return; }
        vacia.style.display = 'none';
        fotos.forEach(function (foto, idx) {
            var wrapper = document.createElement('div');
            wrapper.style.cssText = 'position:relative;border-radius:8px;overflow:hidden;background:#f5f5f5;';
            var img = document.createElement('img');
            img.src = foto.src;
            img.alt = foto.caption || '';
            img.loading = 'lazy';
            img.style.cssText = 'width:100%;height:110px;object-fit:cover;display:block;cursor:pointer;transition:transform 0.2s;';
            img.addEventListener('mouseenter', function () { img.style.transform = 'scale(1.04)'; });
            img.addEventListener('mouseleave', function () { img.style.transform = 'scale(1)'; });
            img.addEventListener('click', function () { abrirLightbox(foto.src, foto.caption); });
            wrapper.appendChild(img);
            if (esDueno) {
                var btnDel = document.createElement('button');
                btnDel.innerHTML = '&times;';
                btnDel.style.cssText = 'position:absolute;top:4px;right:4px;background:rgba(0,0,0,0.55);color:white;border:none;border-radius:50%;width:22px;height:22px;font-size:1rem;cursor:pointer;display:flex;align-items:center;justify-content:center;line-height:1;padding:0;';
                (function (i) {
                    btnDel.addEventListener('click', function (e) {
                        e.stopPropagation();
                        if (!confirm('\u00bfEliminar esta foto?')) return;
                        var f = obtenerGaleria(constructorId);
                        f.splice(i, 1);
                        guardarGaleria(constructorId, f);
                        renderGrid(constructorId);
                    });
                })(idx);
                wrapper.appendChild(btnDel);
            }
            if (foto.caption) {
                var cap = document.createElement('p');
                cap.textContent = foto.caption;
                cap.style.cssText = 'font-size:0.72rem;color:#555;padding:4px 6px;background:white;margin:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
                wrapper.appendChild(cap);
            }
            grid.appendChild(wrapper);
        });
    }

    function abrirLightbox(src, caption) {
        document.getElementById('galeriaLightboxImg').src = src;
        document.getElementById('galeriaLightboxCaption').textContent = caption || '';
        document.getElementById('galeriaLightbox').style.display = 'flex';
    }

    function manejarArchivos(e) {
        var errorEl = document.getElementById('galeriaUploadError');
        errorEl.style.display = 'none';
        var archivos = Array.from(e.target.files);
        if (!archivos.length) return;
        var procesados = 0, errores = [];
        archivos.forEach(function (archivo) {
            if (!archivo.type.startsWith('image/')) {
                errores.push('"' + archivo.name + '" no es imagen.');
                if (++procesados === archivos.length) finalizar(errores);
                return;
            }
            if (archivo.size > 5 * 1024 * 1024) {
                errores.push('"' + archivo.name + '" supera 5 MB.');
                if (++procesados === archivos.length) finalizar(errores);
                return;
            }
            var reader = new FileReader();
            reader.onload = function (ev) {
                var fotos = obtenerGaleria(idActivo);
                fotos.push({ src: ev.target.result, caption: archivo.name.replace(/\.[^.]+$/, ''), fecha: new Date().toLocaleDateString('es-CR') });
                guardarGaleria(idActivo, fotos);
                if (++procesados === archivos.length) finalizar(errores);
            };
            reader.onerror = function () {
                errores.push('Error leyendo "' + archivo.name + '".');
                if (++procesados === archivos.length) finalizar(errores);
            };
            reader.readAsDataURL(archivo);
        });
        e.target.value = '';
    }

    function finalizar(errores) {
        renderGrid(idActivo);
        if (errores.length) {
            var el = document.getElementById('galeriaUploadError');
            el.textContent = errores.join(' \u00b7 ');
            el.style.display = 'block';
        }
    }

    // Delegacion de eventos: captura clics en .btn-galeria aunque sean dinamicos
    document.addEventListener('click', function (e) {
        var btn = e.target.closest('.btn-galeria');
        if (!btn) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        var id = parseInt(btn.dataset.id);
        var nombre = btn.dataset.nombre || '';
        if (!id) return;
        abrirGaleriaModal(id, nombre);
    });

    document.addEventListener('DOMContentLoaded', crearModal);
    window.abrirGaleriaModal = abrirGaleriaModal;

})();
